import React, {useMemo} from "react";
import {Heading, Text, type ICardProps} from "@lmb/kitsconcertomobile";
import {ResponsiveElement, useSeparator} from "../../../../Factory";
import type {ICardComponent} from "@lmb/kitsconcerto-types";
import {useComponentDefaults} from "@lmb/kitsconcerto/Hooks";

const Card = (rawProps: ICardComponent<Omit<ICardProps, 'title'>>) => {
    const {mergedProps: cardProps, themeStyle} = useComponentDefaults('Card', rawProps);
    const {
        title,
        subTitle,
        header,
        footer,
        className,
        variant = 'elevated',
        size = 'md',
        ref,
        children: CardChildren,
        localProps,
        ...props
    } = cardProps;
    const {cssProps, nativeProps} = useSeparator<any>({
        variant,
        size,
        ...props
    });

    const children = useMemo(() => {
        const ret:any[] = [];

        if (header) {
            ret.push(React.isValidElement(header)
                ? React.cloneElement(header, { key: 'header' })
                : <React.Fragment key="header">
                    {typeof header == 'function' ? localProps ? header(localProps) : "" : header}
                </React.Fragment>);
        }

        if (title) {
            ret.push(
                <Heading key="title" size="md" className="mb-1">
                    {typeof title == 'function' ? localProps ? title(localProps) : "" : title}
                </Heading>
            );
        }

        if (subTitle) {
            ret.push(<Text key="subTitle">
                {typeof subTitle == 'function' ? localProps ? subTitle(localProps) : "" : subTitle}
            </Text>);
        }

        if (CardChildren) {
            ret.push(React.isValidElement(CardChildren)
                ? React.cloneElement(CardChildren, { key: 'CardChildren' })
                : <React.Fragment key="CardChildren">{CardChildren}</React.Fragment>);
        }

        if (footer) {
            ret.push(React.isValidElement(footer)
                ? React.cloneElement(footer, { key: 'footer' })
                : <React.Fragment key="footer">
                    {typeof footer == 'function' ? localProps ? footer(localProps) : "" : footer}
            </React.Fragment>);
        }
        return <>{ret}</>;
    }, [header, title, subTitle, CardChildren]);


    const classes = useMemo(() => {
        const classes: string[] = [];
        classes.push('shadow-hard-1')

        if(className){
            classes.push(className)
        }

        return classes.join(" ");
    }, [className]);

    const { entering, exiting, ...restNativeProps } = nativeProps;

    return (
        <ResponsiveElement
            ref={ref}
            entering={entering}
            exiting={exiting}
            additionalStyles={{
                display: "flex",
            }}
            additionalClasses={classes}
            cssProps={{...themeStyle, ...cssProps}}
            nativeProps={restNativeProps}
            as={'Card'}
            children={children}
        />
    );
}

export default Card;
